#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

struct Node{
    int son[26],fail;
}tr[N];

int n,tot=1,dfn[N],sz[N],num,idx[N],c[N],q[N];
int head[N],ver[N],nxt[N],cnt=0;
char s[N*10];

inline void add(int x,int k){
    for(;x<=tot;x+=(x&(-x)))
        c[x]+=k;
}

inline int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

inline void Insert(int x){
    int p=1;
    for(int i=0;s[i];i++){
        if(!tr[p].son[s[i]-'a'])
            tr[p].son[s[i]-'a']=++tot;
        p=tr[p].son[s[i]-'a'];
    }
    idx[x]=p;
}

inline void add_edge(int x,int y){
    ver[++cnt]=y,nxt[cnt]=head[x],head[x]=cnt;
}

inline void dfs(int x){
    dfn[x]=++num;
    sz[x]=1;
    for(int i=head[x];i;i=nxt[i]){
        dfs(ver[i]);
        sz[x]+=sz[ver[i]];
    }
}

inline void build(){
    int hh=1,tt=0;
    tr[1].fail=1;
    for(int i=0;i<26;i++)
        if(tr[1].son[i]){
            q[++tt]=tr[1].son[i];
            tr[tr[1].son[i]].fail=1;
        }else
            tr[1].son[i]=1;
    while(hh<=tt){
        int x=q[hh];
        hh++;
        for(int i=0;i<26;i++)
            if(tr[x].son[i]){
                tr[tr[x].son[i]].fail=tr[tr[x].fail].son[i];
                q[++tt]=tr[x].son[i];
            }else
                tr[x].son[i]=tr[tr[x].fail].son[i];
    }
    for(int i=2;i<=tot;i++)
        add_edge(tr[i].fail,i);
    dfs(1);
}

inline void solve(){
    int p=1;
    for(int i=0;s[i];i++){
        p=tr[p].son[s[i]-'a'];
        add(dfn[p],1);
    }
    for(int i=1,x;i<=n;i++){
        x=idx[i];
        printf("%d\n",ask(dfn[x]+sz[x]-1)-ask(dfn[x]-1));
    }
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%s",s);
        Insert(i);
    }
    build();
    scanf("%s",s);
    solve();
    return 0;
}
